function headerCell(text) {
  return `<th style="background-color:#f8fafc; color:#334155; font-size:11px; line-height:15px; font-weight:bold; text-align:left; padding:8px 7px; border-bottom:1px solid #dbe3ec; white-space:nowrap;">${escapeHtml(text)}</th>`;
